const current = $input.first().json || {};
const API_KEY = String(current.apiFootballKey || '').trim();

if (!API_KEY) {
  throw new Error(
    'مفتاح API-Football غير موجود. ضع المفتاح في حقل apiFootballKey داخل عقدة Load API Configuration.'
  );
}

let apiRequestCount = 0;

const input = String(
  current.chatInput ||
  current.message?.text ||
  current.text ||
  current.input ||
  ''
).trim();

if (!input) {
  throw new Error(
    'أرسل Fixture ID أو اسم المباراة، مثل: Argentina vs France 2022-12-18'
  );
}

const base = 'https://v3.football.api-sports.io';

const headers = {
  'x-apisports-key': API_KEY,
  Accept: 'application/json'
};

function buildQuery(qs = {}) {
  const entries = Object.entries(qs).filter(
    ([_, value]) =>
      value !== undefined &&
      value !== null &&
      value !== ''
  );

  if (!entries.length) {
    return '';
  }

  return (
    '?' +
    entries
      .map(
        ([key, value]) =>
          `${encodeURIComponent(key)}=${encodeURIComponent(value)}`
      )
      .join('&')
  );
}

async function get(path, qs = {}) {
  apiRequestCount += 1;

  const url = `${base}${path}${buildQuery(qs)}`;

  const res = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers,
    json: true,
    timeout: 60000,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });

  const body = res.body || {};

  if (body.errors && Object.keys(body.errors).length) {
    throw new Error(
      `API-Football أعاد خطأ عند طلب ${path}: ${JSON.stringify(body.errors)}`
    );
  }

  return {
    ok: res.statusCode >= 200 && res.statusCode < 300,
    statusCode: res.statusCode,
    url,
    body
  };
}

function parseTeams(text) {
  const cleaned = text
    .replace(/×/g, ' vs ')
    .replace(/\s+ضد\s+/g, ' vs ')
    .replace(/\s+-\s+/g, ' vs ');

  const parts = cleaned
    .split(/\s+vs\s+/i)
    .map(value => value.trim())
    .filter(Boolean);

  if (parts.length !== 2) {
    return null;
  }

  return {
    teamA: parts[0],
    teamB: parts[1]
  };
}

async function findTeamId(name) {
  const aliases = {
    psg: 'Paris Saint Germain',
    'paris saint-germain': 'Paris Saint Germain',
    'paris saint germain': 'Paris Saint Germain',
    'man city': 'Manchester City',
    'man united': 'Manchester United',
    'man utd': 'Manchester United',
    bayern: 'Bayern Munich'
  };

  const normalizedName = name.toLowerCase().trim();
  const searchName = aliases[normalizedName] || name;

  const res = await get.call(this, '/teams', {
    search: searchName
  });

  if (!res.ok) {
    throw new Error(
      `فشل البحث عن الفريق ${name}. API status: ${res.statusCode}`
    );
  }

  const teams = res.body?.response || [];

  if (!teams.length) {
    throw new Error(`لم أجد الفريق: ${name}`);
  }

  const exactMatches = teams.filter(
    item =>
      item.team?.name?.toLowerCase() === searchName.toLowerCase()
  );

  if (exactMatches.length === 1) {
    return {
      id: exactMatches[0].team.id,
      name: exactMatches[0].team.name,
      country: exactMatches[0].team.country || null
    };
  }

  const partialMatches = teams.filter(item =>
    item.team?.name
      ?.toLowerCase()
      .includes(searchName.toLowerCase())
  );

  if (partialMatches.length === 1) {
    return {
      id: partialMatches[0].team.id,
      name: partialMatches[0].team.name,
      country: partialMatches[0].team.country || null
    };
  }

  const candidates = (
    partialMatches.length ? partialMatches : teams
  )
    .slice(0, 5)
    .map(
      item =>
        `${item.team?.name} (${item.team?.country || 'country unavailable'})`
    )
    .join('، ');

  throw new Error(
    `اسم الفريق غير محدد بما يكفي: ${name}. النتائج المحتملة: ${candidates}`
  );
}

async function resolveFixtureId() {
  const dateMatch = input.match(
    /\b(20\d{2}-\d{2}-\d{2})\b/
  )?.[1];

  const inputWithoutDate = input
    .replace(/\b20\d{2}-\d{2}-\d{2}\b/g, '')
    .trim();

  const directId = inputWithoutDate.match(
    /^\s*(\d{4,10})\s*$/
  )?.[1];

  if (directId) {
    return {
      fixtureId: directId,
      resolvedBy: 'direct_fixture_id',
      requestedDate: null,
      detectedTeams: null,
      selectedFixture: null
    };
  }

  const teams = parseTeams(inputWithoutDate);

  if (!teams) {
    throw new Error(
      'اكتب المباراة بهذا الشكل: Argentina vs France 2022-12-18، أو أرسل Fixture ID فقط.'
    );
  }

  const teamA = await findTeamId.call(
    this,
    teams.teamA
  );

  const teamB = await findTeamId.call(
    this,
    teams.teamB
  );

  let selected = null;

  if (dateMatch) {
    const fixturesRes = await get.call(
      this,
      '/fixtures',
      {
        date: dateMatch,
        team: teamA.id
      }
    );

    if (!fixturesRes.ok) {
      throw new Error(
        `فشل البحث عن مباريات تاريخ ${dateMatch}. API status: ${fixturesRes.statusCode}`
      );
    }

    const fixtures =
      fixturesRes.body?.response || [];

    selected = fixtures.find(fixture => {
      const homeId =
        fixture.teams?.home?.id;

      const awayId =
        fixture.teams?.away?.id;

      return (
        (homeId === teamA.id &&
          awayId === teamB.id) ||
        (homeId === teamB.id &&
          awayId === teamA.id)
      );
    });
  }

  if (!selected && dateMatch) {
    throw new Error(
      `لم أجد المباراة بين ${teamA.name} و${teamB.name} بتاريخ ${dateMatch}. لن يتم اختيار مباراة مختلفة تلقائيًا.`
    );
  }

  if (!selected) {
    const h2hRes = await get.call(
      this,
      '/fixtures/headtohead',
      {
        h2h: `${teamA.id}-${teamB.id}`
      }
    );

    if (!h2hRes.ok) {
      throw new Error(
        `فشل البحث في سجل المواجهات. API status: ${h2hRes.statusCode}`
      );
    }

    const fixtures =
      h2hRes.body?.response || [];

    if (!fixtures.length) {
      throw new Error(
        `لم أجد مباريات بين ${teamA.name} و${teamB.name}`
      );
    }

    fixtures.sort(
      (a, b) =>
        new Date(
          b.fixture?.date || 0
        ).getTime() -
        new Date(
          a.fixture?.date || 0
        ).getTime()
    );

    selected =
      fixtures.find(fixture =>
        ['FT', 'AET', 'PEN'].includes(
          fixture.fixture?.status?.short
        )
      ) || fixtures[0];
  }

  if (!selected?.fixture?.id) {
    throw new Error(
      'لم أتمكن من العثور على Fixture ID للمباراة.'
    );
  }

  return {
    fixtureId: String(selected.fixture.id),

    resolvedBy: dateMatch
      ? 'team_names_with_date'
      : 'team_names_h2h',

    requestedDate: dateMatch || null,

    detectedTeams: {
      teamA,
      teamB
    },

    selectedFixture: {
      id: selected.fixture.id,
      date: selected.fixture.date,
      timestamp:
        selected.fixture.timestamp || null,
      timezone:
        selected.fixture.timezone || null,
      status:
        selected.fixture.status?.long || null,
      statusShort:
        selected.fixture.status?.short || null,
      leagueId:
        selected.league?.id || null,
      league:
        selected.league?.name || null,
      season:
        selected.league?.season || null,
      round:
        selected.league?.round || null,
      homeId:
        selected.teams?.home?.id || null,
      home:
        selected.teams?.home?.name || null,
      awayId:
        selected.teams?.away?.id || null,
      away:
        selected.teams?.away?.name || null,
      score: `${selected.goals?.home ?? '-'} - ${selected.goals?.away ?? '-'}`
    }
  };
}

const resolved =
  await resolveFixtureId.call(this);

const fixtureId = resolved.fixtureId;

const [
  fixtureRes,
  statsRes,
  eventsRes,
  lineupsRes,
  playersRes
] = await Promise.all([
  get.call(this, '/fixtures', {
    id: fixtureId
  }),

  get.call(this, '/fixtures/statistics', {
    fixture: fixtureId
  }),

  get.call(this, '/fixtures/events', {
    fixture: fixtureId
  }),

  get.call(this, '/fixtures/lineups', {
    fixture: fixtureId
  }),

  get.call(this, '/fixtures/players', {
    fixture: fixtureId
  })
]);

const fixture =
  fixtureRes.body?.response?.[0];

if (!fixture) {
  return [
    {
      json: {
        success: false,
        fixtureId,
        message:
          'تم تحديد Fixture ID، لكن لم تُرجع API بيانات المباراة.',
        resolved,
        apiUsage: {
          requestCount: apiRequestCount
        },
        debug: fixtureRes.body
      }
    }
  ];
}

/*
 * سجل موحد للاعبين.
 * يستخدم Player ID باعتباره الهوية الأساسية.
 * إذا توفر أكثر من اسم للاعب نفسه، يتم اختيار الاسم الأطول.
 */
const playerRegistry = new Map();

function registerPlayer(player) {
  const id = player?.id;
  const name = String(
    player?.name || ''
  ).trim();

  if (
    id === undefined ||
    id === null
  ) {
    return;
  }

  const key = String(id);
  const existing =
    playerRegistry.get(key);

  if (
    !existing ||
    name.length >
      String(existing.name || '').length
  ) {
    playerRegistry.set(key, {
      id,
      name: name || existing?.name || null
    });
  }
}

for (
  const lineup of
  lineupsRes.body?.response || []
) {
  for (
    const item of
    lineup.startXI || []
  ) {
    registerPlayer(item.player);
  }

  for (
    const item of
    lineup.substitutes || []
  ) {
    registerPlayer(item.player);
  }
}

for (
  const teamBlock of
  playersRes.body?.response || []
) {
  for (
    const item of
    teamBlock.players || []
  ) {
    registerPlayer(item.player);
  }
}

for (
  const event of
  eventsRes.body?.response || []
) {
  registerPlayer(event.player);
  registerPlayer(event.assist);
}

function resolvePlayer(player) {
  if (!player) {
    return {
      id: null,
      name: null,
      label: null
    };
  }

  const id =
    player.id ?? null;

  const registered =
    id !== null
      ? playerRegistry.get(String(id))
      : null;

  const name =
    registered?.name ||
    player.name ||
    null;

  return {
    id,
    name,
    label:
      name && id !== null
        ? `${name} [ID:${id}]`
        : name
  };
}

function compactStats(stats) {
  return (stats || []).map(
    teamBlock => ({
      teamId:
        teamBlock.team?.id || null,
      team:
        teamBlock.team?.name || null,

      statistics: (
        teamBlock.statistics || []
      ).map(stat => ({
        type: stat.type,
        value: stat.value
      }))
    })
  );
}

function compactEvents(events) {
  return (events || []).map(
    event => {
      const player =
        resolvePlayer(event.player);

      const assist =
        resolvePlayer(event.assist);

      return {
        time:
          event.time?.elapsed ?? null,
        extra:
          event.time?.extra ?? null,

        teamId:
          event.team?.id || null,
        team:
          event.team?.name || null,

        playerId: player.id,
        playerName: player.name,
        playerLabel: player.label,

        assistId: assist.id,
        assistName: assist.name,
        assistLabel: assist.label,

        type:
          event.type || null,
        detail:
          event.detail || null,
        comments:
          event.comments || null
      };
    }
  );
}

function compactLineups(lineups) {
  return (lineups || []).map(
    lineup => ({
      teamId:
        lineup.team?.id || null,
      team:
        lineup.team?.name || null,

      formation:
        lineup.formation || null,

      coachId:
        lineup.coach?.id || null,
      coach:
        lineup.coach?.name || null,

      startXI: (
        lineup.startXI || []
      ).map(item => {
        const player =
          resolvePlayer(item.player);

        return {
          id: player.id,
          name: player.name,
          label: player.label,
          number:
            item.player?.number ?? null,
          position:
            item.player?.pos || null,
          grid:
            item.player?.grid || null
        };
      }),

      substitutes: (
        lineup.substitutes || []
      ).map(item => {
        const player =
          resolvePlayer(item.player);

        return {
          id: player.id,
          name: player.name,
          label: player.label,
          number:
            item.player?.number ?? null,
          position:
            item.player?.pos || null
        };
      })
    })
  );
}

function compactPlayers(players) {
  return (players || []).map(
    teamBlock => ({
      teamId:
        teamBlock.team?.id || null,
      team:
        teamBlock.team?.name || null,

      players: (
        teamBlock.players || []
      ).map(item => {
        const player =
          resolvePlayer(item.player);

        const stats =
          item.statistics?.[0] || {};

        return {
          id: player.id,
          name: player.name,
          label: player.label,

          number:
            stats.games?.number ?? null,
          position:
            stats.games?.position || null,
          rating:
            stats.games?.rating ?? null,
          minutes:
            stats.games?.minutes ?? null,

          goals:
            stats.goals?.total ?? null,
          assists:
            stats.goals?.assists ?? null,

          shotsTotal:
            stats.shots?.total ?? null,
          shotsOn:
            stats.shots?.on ?? null,

          passesTotal:
            stats.passes?.total ?? null,
          passesKey:
            stats.passes?.key ?? null,
          passesAccuracy:
            stats.passes?.accuracy ?? null,

          tacklesTotal:
            stats.tackles?.total ?? null,
          interceptions:
            stats.tackles?.interceptions ??
            null,

          duelsTotal:
            stats.duels?.total ?? null,
          duelsWon:
            stats.duels?.won ?? null,

          dribblesAttempts:
            stats.dribbles?.attempts ??
            null,
          dribblesSuccess:
            stats.dribbles?.success ??
            null
        };
      })
    })
  );
}

const matchDate =
  fixture.fixture?.date || null;

const cleanMatchData = {
  source: 'api-football',

  input,

  fixtureId:
    String(fixture.fixture?.id || fixtureId),

  date: matchDate,

  dateOnly: matchDate
    ? matchDate.slice(0, 10)
    : null,

  timestamp:
    fixture.fixture?.timestamp || null,

  timezone:
    fixture.fixture?.timezone || null,

  resolved,

  match:
    `${fixture.teams?.home?.name} vs ${fixture.teams?.away?.name}`,

  homeTeamId:
    fixture.teams?.home?.id || null,
  homeTeam:
    fixture.teams?.home?.name || null,

  awayTeamId:
    fixture.teams?.away?.id || null,
  awayTeam:
    fixture.teams?.away?.name || null,

  score:
    `${fixture.goals?.home ?? '-'} - ${fixture.goals?.away ?? '-'}`,

  status:
    fixture.fixture?.status?.long || null,

  statusShort:
    fixture.fixture?.status?.short || null,

  elapsed:
    fixture.fixture?.status?.elapsed ?? null,

  leagueId:
    fixture.league?.id || null,
  league:
    fixture.league?.name || null,

  season:
    fixture.league?.season || null,

  country:
    fixture.league?.country || null,

  round:
    fixture.league?.round || null,

  venueId:
    fixture.fixture?.venue?.id || null,

  venue:
    fixture.fixture?.venue?.name || null,

  city:
    fixture.fixture?.venue?.city || null,

  referee:
    fixture.fixture?.referee || null,

  statistics: compactStats(
    statsRes.body?.response
  ),

  events: compactEvents(
    eventsRes.body?.response
  ),

  lineups: compactLineups(
    lineupsRes.body?.response
  ),

  players: compactPlayers(
    playersRes.body?.response
  ),

  apiUsage: {
    requestCount: apiRequestCount
  },

  rawStatus: {
    fixtureLoaded:
      fixtureRes.ok,
    statisticsLoaded:
      statsRes.ok,
    eventsLoaded:
      eventsRes.ok,
    lineupsLoaded:
      lineupsRes.ok,
    playersLoaded:
      playersRes.ok,

    statisticsCount:
      statsRes.body?.response?.length || 0,
    eventsCount:
      eventsRes.body?.response?.length || 0,
    lineupsCount:
      lineupsRes.body?.response?.length || 0,
    playersCount:
      playersRes.body?.response?.length || 0
  }
};

return [
  {
    json: {
      success: true,

      fixtureId:
        cleanMatchData.fixtureId,

      date:
        cleanMatchData.date,

      dateOnly:
        cleanMatchData.dateOnly,

      match:
        cleanMatchData.match,

      score:
        cleanMatchData.score,

      matchData:
        cleanMatchData,

      apiUsage: {
        requestCount: apiRequestCount
      }
    }
  }
];

const match = $json.matchData;

if (!match) {
  throw new Error('matchData غير موجود. تأكد أن النود السابقة هي Fetch API-Football Data.');
}

const allPlayers = [];

for (const team of match.players || []) {
  for (const player of team.players || []) {
    allPlayers.push({
      team: team.team,
      ...player,
      id: player.id ?? null,
      name: player.name || null,
      label: player.label || (player.id ? `${player.name} [ID:${player.id}]` : player.name),
      ratingNum: player.rating !== null && player.rating !== undefined ? Number(player.rating) : null
    });
  }
}

function num(value) {
  if (value === null || value === undefined || value === '') return null;
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function topBy(field, limit = 5) {
  return [...allPlayers]
    .filter(p => num(p[field]) !== null)
    .sort((a, b) => num(b[field]) - num(a[field]))
    .slice(0, limit)
    .map(p => ({
      id: p.id,
      name: p.name,
      label: p.label,
      team: p.team,
      position: p.position,
      number: p.number,
      value: p[field],
      rating: p.rating
    }));
}

function getTeamStats(teamName) {
  const block = (match.statistics || []).find(s => s.team === teamName);
  const stats = {};

  for (const item of block?.statistics || []) {
    stats[item.type] = item.value;
  }

  return stats;
}

function statValue(teamName, key) {
  const stats = getTeamStats(teamName);
  return stats[key] ?? null;
}

function goals() {
  return (match.events || [])
    .filter(e => e.type === 'Goal')
    .map(e => ({
      minute: e.extra ? `${e.time}+${e.extra}` : e.time,
      team: e.team,
      scorerId: e.playerId ?? null,
      scorerName: e.playerName || null,
      scorerLabel: e.playerLabel || e.playerName || null,
      assistId: e.assistId ?? null,
      assistName: e.assistName || null,
      assistLabel: e.assistLabel || e.assistName || null,
      detail: e.detail
    }));
}

function cards() {
  return (match.events || [])
    .filter(e => e.type === 'Card')
    .map(e => ({
      minute: e.extra ? `${e.time}+${e.extra}` : e.time,
      team: e.team,
      playerId: e.playerId ?? null,
      playerName: e.playerName || null,
      playerLabel: e.playerLabel || e.playerName || null,
      detail: e.detail,
      comments: e.comments
    }));
}

function substitutions() {
  return (match.events || [])
    .filter(e => e.type === 'subst')
    .map(e => ({
      minute: e.extra ? `${e.time}+${e.extra}` : e.time,
      team: e.team,
      playerOutId: e.playerId ?? null,
      playerOutName: e.playerName || null,
      playerOutLabel: e.playerLabel || e.playerName || null,
      playerInId: e.assistId ?? null,
      playerInName: e.assistName || null,
      playerInLabel: e.assistLabel || e.assistName || null,
      detail: e.detail
    }));
}

function lineups() {
  return (match.lineups || []).map(l => ({
    team: l.team,
    formation: l.formation,
    coach: l.coach,
    startXI: (l.startXI || []).map(p => ({
      id: p.id ?? null,
      name: p.name,
      label: p.label || (p.id ? `${p.name} [ID:${p.id}]` : p.name),
      number: p.number,
      position: p.position || p.pos || null,
      grid: p.grid
    })),
    substitutes: (l.substitutes || []).map(p => ({
      id: p.id ?? null,
      name: p.name,
      label: p.label || (p.id ? `${p.name} [ID:${p.id}]` : p.name),
      number: p.number,
      position: p.position || p.pos || null
    }))
  }));
}

function formationSummary() {
  return (match.lineups || []).map(l => ({
    team: l.team,
    formation: l.formation,
    coach: l.coach
  }));
}

function teamComparison() {
  const home = match.homeTeam;
  const away = match.awayTeam;

  return {
    possession: {
      [home]: statValue(home, 'Ball Possession'),
      [away]: statValue(away, 'Ball Possession')
    },
    totalShots: {
      [home]: statValue(home, 'Total Shots'),
      [away]: statValue(away, 'Total Shots')
    },
    shotsOnGoal: {
      [home]: statValue(home, 'Shots on Goal'),
      [away]: statValue(away, 'Shots on Goal')
    },
    shotsInsideBox: {
      [home]: statValue(home, 'Shots insidebox'),
      [away]: statValue(away, 'Shots insidebox')
    },
    corners: {
      [home]: statValue(home, 'Corner Kicks'),
      [away]: statValue(away, 'Corner Kicks')
    },
    passes: {
      [home]: statValue(home, 'Total passes'),
      [away]: statValue(away, 'Total passes')
    },
    passAccuracy: {
      [home]: statValue(home, 'Passes %'),
      [away]: statValue(away, 'Passes %')
    },
    expectedGoals: {
      [home]: statValue(home, 'expected_goals'),
      [away]: statValue(away, 'expected_goals')
    },
    fouls: {
      [home]: statValue(home, 'Fouls'),
      [away]: statValue(away, 'Fouls')
    },
    yellowCards: {
      [home]: statValue(home, 'Yellow Cards'),
      [away]: statValue(away, 'Yellow Cards')
    },
    goalkeeperSaves: {
      [home]: statValue(home, 'Goalkeeper Saves'),
      [away]: statValue(away, 'Goalkeeper Saves')
    }
  };
}

function availableSections() {
  const sections = [];
  if (match.statistics?.length) sections.push('team_statistics');
  if (match.events?.length) sections.push('events');
  if (match.lineups?.length) sections.push('lineups');
  if (match.players?.length) sections.push('player_statistics');
  return sections;
}

function missingSections() {
  const missing = [];
  if (!match.statistics?.length) missing.push('team_statistics');
  if (!match.events?.length) missing.push('events');
  if (!match.lineups?.length) missing.push('lineups');
  if (!match.players?.length) missing.push('player_statistics');
  missing.push('attack_momentum');
  missing.push('heatmaps');
  missing.push('average_positions');
  missing.push('pass_network');
  missing.push('pressure_map');
  return missing;
}

function dataQualityScore() {
  let score = 0;
  if (match.statistics?.length) score += 25;
  if (match.events?.length) score += 25;
  if (match.lineups?.length) score += 25;
  if (match.players?.length) score += 25;
  return `${score}/100`;
}

function topPlayersByTeam() {
  const byTeam = {};

  for (const p of allPlayers) {
    if (!byTeam[p.team]) byTeam[p.team] = [];
    byTeam[p.team].push(p);
  }

  const result = {};

  for (const [team, players] of Object.entries(byTeam)) {
    result[team] = players
      .filter(p => p.ratingNum !== null)
      .sort((a, b) => b.ratingNum - a.ratingNum)
      .slice(0, 5)
      .map(p => ({
        id: p.id,
        name: p.name,
        label: p.label,
        position: p.position,
        rating: p.rating,
        minutes: p.minutes,
        goals: p.goals,
        assists: p.assists,
        passesTotal: p.passesTotal,
        passesKey: p.passesKey,
        tacklesTotal: p.tacklesTotal,
        interceptions: p.interceptions,
        duelsWon: p.duelsWon
      }));
  }

  return result;
}

